import React, { useState, useContext } from "react";
import { Link, useNavigate, useLocation } from "react-router-dom";
import axios from "../api/axios";
import toast from "react-hot-toast";
import { AuthContext } from "../context/AuthContext";

const Login = () => {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [loading, setLoading] = useState(false);
  const { login } = useContext(AuthContext);
  const navigate = useNavigate();
  const location = useLocation();
  const from = location.state?.from?.pathname || "/";

  const handleSubmit = async e => {
    e.preventDefault();
    try {
      setLoading(true);
      const { data } = await axios.post("/auth/login", { email, password });
      login(data);
      toast.success(`Welcome back, ${data.name}!`);
      navigate(data.role === "admin" ? "/admin" : from, { replace: true });
    } catch (err) {
      toast.error(err.response?.data?.message || "Invalid credentials");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="auth-page">

      {/* LEFT SIDE - Maruti Swift */}
      <div style={{
        position: "relative",
        minHeight: "100vh",
        overflow: "hidden",
        background: "linear-gradient(135deg, #0f172a 0%, #1e3a5f 60%, #1e40af 100%)"
      }}>
        <img
          src="https://stimg.cardekho.com/images/carexteriorimages/930x620/Maruti/Swift/9481/1677913297238/front-left-side-47.jpg"
          alt="Maruti Swift"
          style={{ position:"absolute", inset:0, width:"100%", height:"100%", objectFit:"cover", opacity:0.45, zIndex:0 }}
          onError={e => {
            e.target.src = "https://stimg.cardekho.com/images/carexteriorimages/930x620/Maruti/Swift/9481/1708947156954/front-left-side-47.jpg";
            e.target.onerror = () => { e.target.style.display = "none"; };
          }}
        />
        <div style={{
          position:"absolute", inset:0, zIndex:1,
          background:"linear-gradient(135deg, rgba(15,23,42,0.7) 0%, rgba(30,64,175,0.5) 100%)"
        }} />
        <div style={{
          position:"absolute", bottom:52, left:44, right:44, zIndex:2
        }}>
          <p style={{ fontFamily:"'Syne',sans-serif", fontSize:"1.9rem", fontWeight:800, lineHeight:1.2, marginBottom:14, color:"#fff" }}>
            Drive your <span style={{color:"#60a5fa"}}>dream car</span> — book in seconds.
          </p>
          <p style={{ color:"rgba(255,255,255,0.55)", fontSize:"0.88rem" }}>
            Join thousands of drivers across India
          </p>
        </div>
      </div>

      {/* RIGHT SIDE */}
      <div className="auth-right">
        <div className="auth-box">
          <div className="auth-logo" onClick={() => navigate("/")}>🚗 <span>Drive</span>Premium</div>
          <h1 className="auth-title">Welcome back</h1>
          <p className="auth-sub">Sign in to manage your bookings and explore our fleet.</p>
          <form onSubmit={handleSubmit}>
            <div className="form-group">
              <label>Email</label>
              <input type="email" placeholder="you@example.com" value={email} onChange={e => setEmail(e.target.value)} required />
            </div>
            <div className="form-group">
              <label>Password</label>
              <input type="password" placeholder="••••••••" value={password} onChange={e => setPassword(e.target.value)} required />
            </div>
            <button type="submit" className="btn-primary btn-full" style={{ marginTop:8 }} disabled={loading}>
              {loading ? "Signing in..." : "Sign In →"}
            </button>
          </form>
          <div className="auth-footer-link">
            Don't have an account? <Link to="/register">Create one free</Link>
          </div>
        </div>
      </div>
    </div>
  );
};
export default Login;
